def preprocess_input_exprs_arg_string(input_exprs_str):
    # Sanitize input expressions using ast.literal_eval
    input_exprs_str = re.sub(r'[^a-zA-Z0-9\s\+\-\*\/\=\>\&\|\!\=\(\)]', '', input_exprs_str)
    input_exprs = []
    for input_raw in input_exprs_str.split(';'):
        input_key, expr = input_raw.strip().split('=')
        try:
            input_exprs.append((input_key, ast.literal_eval(expr)))
        except (SyntaxError, NameError, TypeError):
